const payload = $input.first().json;
const workflow = payload.workflow?.name ?? 'unknown';
const execution = payload.execution?.id ?? 'unknown';
const message = payload.execution?.error?.message ?? payload.trigger?.error?.message ?? 'unknown error';

return [{
  json: {
    event: {
      market: 'shared',
      env: 'dry_run',
      stage: 'error',
      decision: 'error',
      reject_reason: message,
      workflow_name: workflow,
      execution_id: String(execution),
      payload: {
        workflow_id: payload.workflow?.id,
        last_node: payload.execution?.lastNodeExecuted,
        mode: payload.execution?.mode,
        raw: payload,
      },
    },
    obsidian_line: `- ${new Date().toISOString()} **${workflow}**: ${message}`,
  },
}];
